output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?manufacturer ?manufacturerLabel ?owner ?ownerLabel WHERE {
  VALUES ?manufacturer {
    wd:Q53268 wd:Q156578 wd:Q97439162
  }
  OPTIONAL {
    ?manufacturer wdt:P127 ?owner .
  }
  OPTIONAL {
    ?manufacturer wdt:P749 ?owner .
  }
  ?manufacturer rdfs:label ?manufacturerLabel .
  ?owner rdfs:label ?ownerLabel .
  FILTER(LANG(?manufacturerLabel) = "en")
  FILTER(LANG(?ownerLabel) = "en")
}

